const item = $input.first().json;

function extractJson(value) {
  if (value && typeof value === 'object' && (value.prompt_entries || value.document_title || value.library_name)) {
    return value;
  }

  const raw = String(value?.response || value?.text || value?.output || value?.result || '').trim();
  if (!raw) throw new Error('AI did not return text or structured JSON.');

  const cleaned = raw
    .replace(/^```[a-zA-Z]*\n?/, '')
    .replace(/```$/, '')
    .trim();

  try {
    return JSON.parse(cleaned);
  } catch (_) {
    const firstBrace = cleaned.indexOf('{');
    const lastBrace = cleaned.lastIndexOf('}');
    if (firstBrace >= 0 && lastBrace > firstBrace) {
      return JSON.parse(cleaned.slice(firstBrace, lastBrace + 1));
    }
  }

  throw new Error('AI did not return usable JSON. Rerun the workflow or use a model that supports JSON output.');
}

function list(items) {
  if (!Array.isArray(items) || items.length === 0) return '- None added';
  return items.map((value) => '- ' + String(value)).join('\n');
}

function placeholders(text) {
  const found = String(text || '').match(/\{[a-zA-Z0-9_\- ]+\}/g) || [];
  return [...new Set(found.map((value) => value.replace(/\s+/g, '_').toLowerCase()))];
}

function fallbackVariables(entry, promptText) {
  const fromPrompt = placeholders(promptText);
  if (fromPrompt.length) return fromPrompt;
  const lower = [entry.title, entry.description, entry.use_case, promptText].join(' ').toLowerCase();
  if (lower.includes('article') || lower.includes('intro') || lower.includes('draft')) return ['{draft}', '{audience}', '{goal}'];
  if (lower.includes('newsletter') || lower.includes('subject')) return ['{update_summary}', '{audience}', '{tone}'];
  if (lower.includes('research')) return ['{research_notes}', '{decision_needed}', '{constraints}'];
  if (lower.includes('workflow') || lower.includes('n8n')) return ['{workflow_description}', '{tools_used}', '{failure_risks}'];
  if (lower.includes('task') || lower.includes('note')) return ['{notes}', '{priority_rules}', '{deadline_context}'];
  return ['{input}', '{goal}', '{constraints}'];
}

function expandPrompt(entry, originalPrompt) {
  const description = entry.description || 'Complete the task clearly and practically.';
  const useCase = String(entry.use_case || 'this task needs a reusable AI prompt')
    .replace(/^use\s+when\s+/i, '')
    .replace(/^when\s+/i, '')
    .replace(/[.!?]+$/g, '');
  const vars = fallbackVariables(entry, originalPrompt);
  const lower = [entry.title, description, useCase, originalPrompt].join(' ').toLowerCase();

  let format = 'Return a clear, skimmable response with headings, concise bullets only where useful, and a short human review checklist at the end.';
  let constraints = 'Do not invent facts. If information is missing, state the assumption or ask a clarifying question before making a recommendation.';

  if (lower.includes('research')) {
    format = 'Return a plain-English summary, key findings, risks or weak spots, three practical next steps, and sources or facts that need verification.';
    constraints = 'Do not overstate certainty. Separate confirmed details from interpretation. Flag missing context clearly.';
  } else if (lower.includes('task') || lower.includes('notes')) {
    format = 'Return a short summary, prioritized action items, parked ideas, open questions, and a final next-action recommendation.';
    constraints = 'Separate real tasks from vague ideas. Keep tasks action-oriented, assign priority where useful, and flag anything that needs human review.';
  } else if (lower.includes('article') || lower.includes('intro') || lower.includes('draft')) {
    format = 'Return one revised version, then a short note explaining what changed and why.';
    constraints = 'Keep the original meaning. Make the writing clearer, warmer, and less salesy. Do not add claims the draft does not support.';
  } else if (lower.includes('newsletter') || lower.includes('subject')) {
    format = 'Return 10 subject line options grouped by angle, plus the 3 strongest picks and a one-sentence reason for each.';
    constraints = 'Avoid clickbait. Keep the tone useful and specific. Make sure each option matches the update and audience.';
  } else if (lower.includes('workflow') || lower.includes('n8n')) {
    format = 'Return the workflow purpose, required inputs, expected output, likely failure points, security concerns, and suggested improvements.';
    constraints = 'Focus on practical reliability. Point out brittle steps, missing error handling, credential risks, and where human review belongs.';
  }

  return [
    'Role: You are a practical AI workflow assistant helping a human turn rough input into a useful result.',
    '',
    'Context: Use this prompt when ' + String(useCase).replace(/^when\s+/i, '') + '.',
    '',
    'Input variables: ' + vars.join(', '),
    '',
    'Task: ' + description + ' Use the provided input to complete the task in a way that is specific, reusable, and easy for a human to review.',
    '',
    'Output format: ' + format,
    '',
    'Constraints: ' + constraints
  ].join('\n');
}

function isWeakStarterPrompt(promptText) {
  const text = String(promptText || '').trim();
  const lower = text.toLowerCase();
  if (text.length < 360) return true;
  const intakePatterns = [
    'please provide',
    'provide the',
    'send me',
    'share your',
    'tell me',
    "i'll help",
    'i will help',
    'once you provide',
    'please note that this prompt'
  ];
  if (intakePatterns.some((pattern) => lower.includes(pattern))) return true;

  const usefulSections = ['role:', 'context:', 'task:', 'output format:', 'constraints:'];
  const sectionCount = usefulSections.filter((section) => lower.includes(section)).length;
  return sectionCount < 3;
}

function normalizeEntry(entry) {
  const originalPrompt = String(entry.copy_ready_prompt || '').trim();
  const needsExpansion = isWeakStarterPrompt(originalPrompt);
  const copyReadyPrompt = needsExpansion ? expandPrompt(entry, originalPrompt) : originalPrompt;
  const promptVariables = fallbackVariables(entry, copyReadyPrompt);
  return {
    ...entry,
    tags: Array.isArray(entry.tags) && entry.tags.length ? entry.tags : ['starter-prompt', 'human-review'],
    variables: needsExpansion ? promptVariables : (Array.isArray(entry.variables) && entry.variables.length ? entry.variables : promptVariables),
    copy_ready_prompt: copyReadyPrompt,
    quality_note: entry.quality_note || 'Review the output for accuracy, missing context, and whether it matches the intended use before saving it permanently.'
  };
}

function entryMarkdown(entries) {
  if (!Array.isArray(entries) || entries.length === 0) return 'No prompt entries were generated.';
  return entries.map(normalizeEntry).map((entry, index) => {
    return '### ' + (index + 1) + '. ' + (entry.title || 'Untitled Prompt') + '\n\n' +
      '**Category:** ' + (entry.category || 'Uncategorized') + '\n\n' +
      '**Description:** ' + (entry.description || 'No description provided.') + '\n\n' +
      '**Use case:** ' + (entry.use_case || 'Use when this prompt fits the task.') + '\n\n' +
      '**Tags:** ' + entry.tags.join(', ') + '\n\n' +
      '**Variables:** ' + entry.variables.join(', ') + '\n\n' +
      '**Copy-ready prompt:**\n```text\n' + entry.copy_ready_prompt + '\n```\n\n' +
      '**Quality note:** ' + entry.quality_note;
  }).join('\n\n');
}

const parsed = extractJson(item);
const entries = Array.isArray(parsed.prompt_entries) ? parsed.prompt_entries.map(normalizeEntry) : [];
const title = parsed.document_title || parsed.library_name || 'Prompt Starter Library';
const markdown = '# ' + title + '\n\n' +
  '## Summary\n' + (parsed.summary || 'No summary provided.') + '\n\n' +
  '## Library Goal\n' + (parsed.library_goal || 'Create a reusable AI prompt library from rough tasks.') + '\n\n' +
  '## Categories\n' + list(parsed.categories) + '\n\n' +
  '## Prompt Entries\n' + entryMarkdown(entries) + '\n\n' +
  '## Organization Notes\n' + list(parsed.organization_notes) + '\n\n' +
  '## Missing Context Questions\n' + list(parsed.missing_context_questions) + '\n\n' +
  '## Next Steps\n' + list(parsed.next_steps) + '\n\n' +
  '## Human Review Note\n' + (parsed.review_note || 'Review every generated prompt before adding it to your permanent library.');

return [{
  json: {
    workflow_name: 'GP-WF-004 - Prompt Starter Library Builder',
    created_at: new Date().toISOString(),
    document_title: title,
    summary: parsed.summary || '',
    output_markdown: markdown,
    prompt_count: entries.length,
    categories: Array.isArray(parsed.categories) ? parsed.categories : [],
    next_steps: Array.isArray(parsed.next_steps) ? parsed.next_steps : [],
    review_note: parsed.review_note || ''
  }
}];

const today = new Date();
const date = today.toISOString().slice(0, 10);
const workflowName = 'GP-WF-004 - Prompt Library Builder';
const title = $json.document_title || 'Prompt Library';
const cleanOutput = String($json.output_markdown || '').replace(/^# .+\n+/, '').trim();
const body = [
  '# ' + title,
  '',
  'Created: ' + date,
  'Workflow: ' + workflowName,
  $json.prompt_count ? 'Prompts organized: ' + $json.prompt_count : '',
  Array.isArray($json.categories) && $json.categories.length ? 'Categories: ' + $json.categories.join(', ') : '',
  '',
  cleanOutput,
  '',
  'Source: GetPrompting Free Workflow Library'
].filter((line) => line !== '').join('\n');
return [{ json: { ...$json, workflow_name: workflowName, document_title: workflowName + ' - ' + date, document_body: body } }];
